const g=/[\u4e00-\u9fff\u3400-\u4dbf]/;function u(d){const t=[],n=d.toLowerCase(),o=n.length;let e=0;for(;e<o;){const i=n[e];if(g.test(i)){let s=e;for(;s<o&&g.test(n[s]);)s++;const r=n.slice(e,s);if(r.length===1)t.push(r);else for(let c=0;c<r.length-1;c++)t.push(r.slice(c,c+2));e=s}else{let s=e;for(;s<o&&!g.test(n[s]);)s++;const c=n.slice(e,s).match(/[a-z0-9]+/g);c&&t.push(...c),e=s}}return t}export class BM25Search{k1;b;docs=new Map;docLengths=new Map;termFreqs=new Map;invertedIndex=new Map;totalDocLength=0;constructor(t=1.5,n=.75){this.k1=t,this.b=n}addDocument(t,n){this.docs.has(t)&&this.removeDocument(t);const o=u(n);this.docs.set(t,n),this.docLengths.set(t,o.length),this.totalDocLength+=o.length;const e=new Map;for(const i of o)e.set(i,(e.get(i)??0)+1);this.termFreqs.set(t,e);for(const i of e.keys()){let s=this.invertedIndex.get(i);s||(s=new Set,this.invertedIndex.set(i,s)),s.add(t)}}search(t,n=10){const o=this.docs.size;if(o===0)return[];const e=u(t);if(e.length===0)return[];const i=o>0?this.totalDocLength/o:0,s=new Set(e),r=new Map;for(const c of s){const h=this.invertedIndex.get(c);if(!h||h.size===0)continue;const a=h.size,m=Math.log((o-a+.5)/(a+.5)+1);for(const l of h){const f=this.termFreqs.get(l)?.get(c)??0;if(f===0)continue;const p=this.docLengths.get(l)??0,w=f+this.k1*(1-this.b+this.b*(i>0?p/i:0)),L=m*(f*(this.k1+1))/w;r.set(l,(r.get(l)??0)+L)}}return[...r.entries()].map(([c,h])=>({id:c,score:h})).sort((c,h)=>h.score-c.score).slice(0,n)}removeDocument(t){if(!this.docs.has(t))return;const n=this.termFreqs.get(t);if(n)for(const o of n.keys()){const e=this.invertedIndex.get(o);e&&(e.delete(t),e.size===0&&this.invertedIndex.delete(o))}this.totalDocLength-=this.docLengths.get(t)??0,this.docs.delete(t),this.docLengths.delete(t),this.termFreqs.delete(t)}clear(){this.docs.clear(),this.docLengths.clear(),this.termFreqs.clear(),this.invertedIndex.clear(),this.totalDocLength=0}size(){return this.docs.size}}
